export default function PharmacyPage() {
  const [pharmacyList, setPharmacyList] = useState([]);
  const [centerPos, setCenterPos] = useState({ lat: 37.5665, lng: 126.9780 });

  const handleRegionSelect = async (city: string, district: string) => {
    try {
      // 1. 백엔드에서 데이터 가져오기 (이전 코드와 동일) [cite: 2026-02-16]
      const response = await api.get(`/api/pharmacies/region`, {
        params: { city, district }
      });
      setPharmacyList(response.data);

      // 2. 지도 중심 이동 (선택된 구에 데이터가 있다면 첫 번째 약국 위치로 이동) [cite: 2026-02-19]
      if (response.data.length > 0) {
        setCenterPos({ 
          lat: response.data[0].wgs84lat, 
          lng: response.data[0].wgs84lon 
        });
      }
    } catch (error) {
      console.error("검색 실패", error);
    }
  };

  return (
    <div style={{ maxWidth: '1000px', margin: '0 auto', padding: '20px' }}>
      <h2 style={{ marginBottom: '20px' }}>전국 약국 지도</h2>
      
      {/* 🚀 업그레이드된 지역 선택기 */}
      <div style={{ marginBottom: '30px' }}>
        <RegionSelector onRegionSelect={handleRegionSelect} />
      </div>

      <div style={{ height: '500px', borderRadius: '12px', overflow: 'hidden', boxShadow: '0 4px 20px rgba(0,0,0,0.1)' }}>
        <KakaoMap pharmacyList={pharmacyList} centerPos={centerPos} />
      </div>
    </div>
  );
}